const raw = $input.first().json;

// ── SAMPLE ACCESS REQUEST ─────────────────────────────────────────────
// Requester:  Marcus Thompson (m.thompson@company.com)
// System:     AWS Production Account — IAM PowerUser
// Reason:     Need to investigate billing anomaly in prod
// Duration:   Temporary (48 hours)
// Manager:    sarah.kim@company.com
// Ticket:     JIRA-4821
// ─────────────────────────────────────────────────────────────────────

const request = {
  requester: {
    name:       raw.userName       || 'Marcus Thompson',
    email:      raw.userEmail      || 'm.thompson@company.com',
    department: raw.department     || 'Engineering',
    role:       raw.userRole       || 'Backend Engineer'
  },
  access: {
    system:     raw.system         || 'AWS Production Account',
    permission: raw.permission     || 'IAM PowerUser',
    duration:   raw.duration       || 'temporary-48h',
    reason:     raw.reason         || 'Investigate billing anomaly in prod'
  },
  metadata: {
    ticketId:   raw.ticketId       || 'JIRA-4821',
    manager:    raw.managerEmail   || 'sarah.kim@company.com',
    timestamp:  new Date().toISOString()
  }
};

return [{ json: { request } }];

const response = $input.first().json;
let decision;
try {
  const raw = response.result || response.content || response;
  decision = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  decision = { decision: 'needs_approval', reason: 'AI parse error — manual review required', riskScore: 10 };
}
return [{ json: { decision } }];

